  for (const arg of args) {
    if (arg === '--manual') {
      opts.mode = 'manual'
    } else if (arg === '--headless') {
      opts.headless = true
    } else if (arg.startsWith('--pause=')) {
      opts.pauseMs = parseInt(arg.split('=')[1], 10)
    } else if (arg.startsWith('--step=')) {
      opts.startStep = parseInt(arg.split('=')[1], 10)
    } else if (arg.startsWith('--browser=')) {
      const b = arg.split('=')[1] as DemoOptions['browser']
      if (['chromium', 'firefox', 'webkit'].includes(b)) {
        opts.browser = b
      }
    }
  }

  return opts
}

