import { chromium, firefox, webkit } from '@playwright/test'
import { steps } from './steps'
import { showOverlay, waitForAdvance } from './overlay'
import type { DemoOptions } from './types'

const BASE_URL = 'http://localhost:8080'

async function checkServer(url: string, label: string): Promise<{ ok: boolean; detail: string }> {
  try {
    const res = await fetch(url, { signal: AbortSignal.timeout(5000) })
    if (!res.ok) {
      return { ok: false, detail: `${label} responded with HTTP ${res.status}` }
    }
    return { ok: true, detail: '' }
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err)
    return { ok: false, detail: `${label} at ${url} is not reachable: ${msg}` }
  }
}

async function preflight(): Promise<void> {
  const web = await checkServer(BASE_URL, 'Web dev server')
  if (!web.ok) {
    console.error('\n--- Demo preflight failed ---\n')
    console.error(`  - ${web.detail}`)
    console.error('\nStart the dev environment first:  make dev\n')
    process.exit(1)
  }

  // Check the API through the Vite proxy — /graphql is the main proxied endpoint
  const api = await checkServer(`${BASE_URL}/graphql`, 'API server (via proxy)')
  if (!api.ok) {
    console.warn(`\n⚠ ${api.detail}`)
    console.warn('  The demo will run but data-dependent steps may fail or show empty results.\n')
  }
}

function parseArgs(): DemoOptions {
  const args = process.argv.slice(2)
  const opts: DemoOptions = {
    mode: 'auto',
    pauseMs: 3000,
    startStep: 1,
    browser: 'chromium',
    headless: false,
  }

  for (const arg of args) {
    if (arg === '--manual') {
      opts.mode = 'manual'
    } else if (arg === '--headless') {
      opts.headless = true
    } else if (arg.startsWith('--pause=')) {
      opts.pauseMs = parseInt(arg.split('=')[1], 10)
    } else if (arg.startsWith('--step=')) {
      opts.startStep = parseInt(arg.split('=')[1], 10)
    } else if (arg.startsWith('--browser=')) {
      const b = arg.split('=')[1] as DemoOptions['browser']
      if (['chromium', 'firefox', 'webkit'].includes(b)) {
        opts.browser = b
      }
    }
  }

  return opts
}

async function main() {
  const opts = parseArgs()

  await preflight()

  const launchers = { chromium, firefox, webkit }
  const launcher = launchers[opts.browser]

  if (opts.headless) {
    console.log(`\n🧪 College Power Search Demo (headless smoke test)`)
    console.log(`   Steps: ${steps.length}\n`)
  } else {
    console.log(`\n🎬 College Power Search Demo`)
    console.log(
      `   Mode: ${opts.mode === 'manual' ? 'manual (click to advance)' : `auto (${opts.pauseMs}ms pause)`}`,
    )
    console.log(`   Browser: ${opts.browser}`)
    console.log(`   Steps: ${steps.length}\n`)
  }

  const browser = await launcher.launch({
    headless: opts.headless,
    slowMo: opts.headless ? 0 : 50,
  })

  const context = await browser.newContext({
    viewport: { width: 1280, height: 800 },
  })
  const page = await context.newPage()

  const startIndex = Math.max(0, opts.startStep - 1)

  try {
    for (let i = startIndex; i < steps.length; i++) {
      const step = steps[i]
      console.log(`  [${i + 1}/${steps.length}] ${step.title}`)

      // Run the step action
      await step.action(page)

      if (!opts.headless) {
        // Inject the overlay after the action (in case of navigation)
        await showOverlay(page, {
          stepIndex: i,
          totalSteps: steps.length,
          title: step.title,
          description: step.description,
          mode: opts.mode,
          pauseMs: opts.pauseMs,
        })

        // Wait for advance
        if (i < steps.length - 1) {
          await waitForAdvance(page, opts.mode, opts.pauseMs)
        } else {
          // Last step — keep the browser open for the observer
          console.log('\n✅ Demo complete. Close the browser to exit.\n')
          await page.waitForEvent('close', { timeout: 0 }).catch(() => {})
        }
      }
    }

    if (opts.headless) {
      console.log('\n✅ All demo steps passed.\n')
    }
  } catch (err) {
    if (
      !opts.headless &&
      (err as Error).message?.includes('Target page, context or browser has been closed')
    ) {
      console.log('\n👋 Browser closed. Demo ended.\n')
    } else {
      throw err
    }
  } finally {
    await browser.close().catch(() => {})
  }
}

main().catch((err) => {
  console.error('Demo failed:', err)
  process.exit(1)
})

