import { create } from 'zustand'
import { urqlClient } from '@/lib/urqlClient'

const PreferencesQuery = `
  query Preferences {
    preferences {
      homeLatitude
      homeLongitude
      homeState
    }
  }
`

const UpdatePreferencesMutation = `
  mutation UpdatePreferences($input: UpdatePreferencesInput!) {
    updatePreferences(input: $input) {
      homeLatitude
      homeLongitude
      homeState
    }
  }
`

interface PreferencesData {
  homeLatitude: number | null
  homeLongitude: number | null
  homeState: string | null
}

interface PreferencesState extends PreferencesData {
  loaded: boolean
  loading: boolean

  load: () => Promise<void>
  update: (prefs: Partial<PreferencesData>) => Promise<void>
  clear: () => void
}

export const usePreferencesStore = create<PreferencesState>()((set, get) => ({
  homeLatitude: null,
  homeLongitude: null,
  homeState: null,
  loaded: false,
  loading: false,

  load: async () => {
    if (get().loaded || get().loading) return
    set({ loading: true })
    try {
      const result = await urqlClient
        .query<{ preferences: PreferencesData }>(PreferencesQuery, {})
        .toPromise()
      if (result.data?.preferences) {
        const { homeLatitude, homeLongitude, homeState } = result.data.preferences
        set({
          homeLatitude: homeLatitude ?? null,
          homeLongitude: homeLongitude ?? null,
          homeState: homeState ?? null,
          loaded: true,
        })
      }
    } finally {
      set({ loading: false })
    }
  },

  update: async (prefs) => {
    const result = await urqlClient
      .mutation<{ updatePreferences: PreferencesData }>(UpdatePreferencesMutation, { input: prefs })
      .toPromise()
    if (result.data?.updatePreferences) {
      const { homeLatitude, homeLongitude, homeState } = result.data.updatePreferences
      set({
        homeLatitude: homeLatitude ?? null,
        homeLongitude: homeLongitude ?? null,
        homeState: homeState ?? null,
      })
    }
  },

  clear: () => {
    set({
      homeLatitude: null,
      homeLongitude: null,
      homeState: null,
      loaded: false,
      loading: false,
    })
  },
}))

import { useEffect } from 'react'
import { Routes, Route } from 'react-router-dom'
import { Header } from '@/components/layout/Header'
import { Footer } from '@/components/layout/Footer'
import { useWebMCP } from '@/hooks/useWebMCP'
import { useAuthStore } from '@/stores/authStore'
import { usePreferencesStore } from '@/stores/preferencesStore'
import { About } from '@/pages/About'
import { AuthCallback } from '@/pages/AuthCallback'
import { Home } from '@/pages/Home'
import { Search } from '@/pages/Search'

export function App() {
  useWebMCP()

  const initialize = useAuthStore((s) => s.initialize)
  const session = useAuthStore((s) => s.session)
  const loadPreferences = usePreferencesStore((s) => s.load)
  const clearPreferences = usePreferencesStore((s) => s.clear)

  useEffect(() => {
    initialize()
  }, [initialize])

  useEffect(() => {
    if (session) {
      loadPreferences()
    } else {
      clearPreferences()
    }
  }, [session, loadPreferences, clearPreferences])

  return (
    <div style={{ display: 'flex', minHeight: '100vh', flexDirection: 'column' }}>
      <Header />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/auth/callback" element={<AuthCallback />} />
        <Route path="/search" element={<Search />} />
      </Routes>
      <Footer />
    </div>
  )
}

