/**
 * Strict GraphQL utilities — re-exports urql hooks with types that reject raw strings.
 *
 * Use these instead of importing directly from 'urql'. Raw string queries bypass
 * gql.tada's compile-time schema validation. These wrappers require a
 * TypedDocumentNode (returned by gql.tada's graphql()), so TypeScript itself
 * catches invalid field references at build time.
 *
 * Usage:
 *   import { graphql } from 'gql.tada'
 *   import { useQuery, useMutation } from '@/lib/graphql'
 *
 *   const MyQuery = graphql(`query MyQuery { ... }`)
 *   const [result] = useQuery({ query: MyQuery })
 */

import {
  useQuery as _useQuery,
  useMutation as _useMutation,
  type UseQueryResponse,
  type UseMutationResponse,
} from 'urql'
import type { AnyVariables, OperationContext, RequestPolicy } from '@urql/core'
import type { DocumentNode } from '@0no-co/graphql.web'

// Narrow query type: DocumentNode (which TypedDocumentNode extends) but NOT string.
// gql.tada's graphql() returns TadaDocumentNode which extends DocumentNode, so it
// passes this constraint. Raw template strings do not.

interface StrictQueryArgs<
  Variables extends AnyVariables = AnyVariables,
  Data = any,
> {
  query: DocumentNode & { __apiType?: (v: Variables) => Data }
  variables?: Variables
  requestPolicy?: RequestPolicy
  context?: Partial<OperationContext>
  pause?: boolean
}

export function useQuery<
  Data = any,
  Variables extends AnyVariables = AnyVariables,
>(args: StrictQueryArgs<Variables, Data>): UseQueryResponse<Data, Variables> {
  // The cast is safe — we're only narrowing the input type, not widening it.
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useQuery(args as any)
}

export function useMutation<
  Data = any,
  Variables extends AnyVariables = AnyVariables,
>(query: DocumentNode & { __apiType?: (v: Variables) => Data }): UseMutationResponse<Data, Variables> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useMutation(query as any)
}

